// total(items): items is an array of { price, qty }.
// Subtotal = sum of price * qty. If the subtotal is strictly greater than
// 100, apply a 10% discount to the whole order. Return the final total.
function total(items) {
  const subtotal = items.reduce((sum, i) => sum + i.price * i.qty, 0);
  return subtotal > 100 ? subtotal * 0.9 : subtotal;
}
module.exports = { total };
